import { motion } from "motion/react";
import { Menu, X } from "lucide-react";
import { Link } from "react-router-dom";
import { useState } from "react";

const logoImg = "data:image/png;base64,";

export function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <motion.nav
      initial={{ y: -100 }} animate={{ y: 0 }} transition={{ duration: 0.6 }}
      className="fixed top-0 left-0 right-0 z-50 backdrop-blur-xl"
      style={{ background: 'rgba(10,9,6,0.82)', borderBottom: '1px solid rgba(210,110,30,0.2)' }}
    ><div className="w-full px-8">
        <div className="flex items-center justify-between h-26">
          <a href="#" className="flex items-center gap-2 group py-1 pl-1">
<img src={logoImg} alt="ResQAid" className="h-24 w-auto 
        object-contain 
        transition-all duration-300 
        group-hover:scale-102 
        filter drop-shadow-[0_0_15px_rgba(210,110,30,0.5)]" />
          </a>

          <div className="hidden md:flex items-center gap-12">
            {['Platform', 'Features', 'Missions'].map(link => (
              <a key={link} href={`#${link.toLowerCase()}`} className="text-gray-300 text-lg tracking-widest uppercase transition-colors" style={{}} onMouseEnter={e => (e.currentTarget.style.color = '#D26E1E')} onMouseLeave={e => (e.currentTarget.style.color = '')}>
                {link}
              </a>
            ))}
            <Link to="/login" className="px-8 py-3.5 text-white text-base tracking-widest uppercase font-semibold transition-opacity hover:opacity-85" style={{ background: '#D26E1E' }}>
             Request Demo
            </Link>
          </div>

          <button onClick={() => setIsOpen(!isOpen)} className="md:hidden w-10 h-10 flex items-center justify-center text-white">
            {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>

        {isOpen && (
          <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: "auto" }} exit={{ opacity: 0, height: 0 }} className="md:hidden py-6" style={{ borderTop: '1px solid rgba(255,255,255,0.08)' }}>
            <div className="flex flex-col gap-4">
              {['Platform', 'Features', 'Missions'].map(link => (
                <a key={link} href={`#${link.toLowerCase()}`} className="text-gray-300 text-lg tracking-widest uppercase">{link}</a>
              ))}
              <Link to="/login" className="px-8 py-3.5 text-white text-base tracking-widest uppercase font-semibold w-full" style={{ background: '#D26E1E' }}>
                Request Demo
              </Link>
            </div>
          </motion.div>
        )}
      </div>
    </motion.nav>
  );
}
